In square $ABCD$ with sides of length 4 cm, $N$ is the midpoint of side $BC$ and $M$ is the midpoint of side $CD$. What is the area of triangle $AMN$, in $\text{cm}^2$?

\begin{center}
    \begin{asy}
    size(6cm);
    pair a,b,c,d,m,n;
a=(0,10);
b=(10,10);
c=(10,0);
d=(0,0);
m=(5,0);
n=(10,5);
draw(a--b--c--d--cycle);
draw(a--m--n--cycle);
label("4 cm",(5,10),N);
label("$A$",a,N);
label("$B$",b,N);
label("$C$",c,S);
label("$D$",d,S);
label("$M$",m,S);
label("$N$",n,E);pair a,b,c,d,m,n;
a=(0,10);
b=(10,10);
c=(10,0);
d=(0,0);
m=(5,0);
n=(10,5);
draw(a--b--c--d--cycle);
draw(a--m--n--cycle);
label("4 cm",(5,10),N);
label("$A$",a,N);
label("$B$",b,N);
label("$C$",c,S);
label("$D$",d,S);
label("$M$",m,S);
label("$N$",n,E);
    \end{asy}
\end{center}
}

\textbf{Answer:} \begin{align*}
[AMN] &= [ABCD] - [ABN] - [ADM] - [MNC] \\
&= 16 - (1/2)(4)(2) - (1/2)(4)(2) - (1/2)(2)(2)\\
& = 16 - 4 - 4 - 2 = \boxed{6}
\end{align*}

